template:
const std = @import("std");

pub const Expr = union(enum) {
    number: i32,
    add: [[SLOT add_struct]],
    multiply: struct { left: *const Expr, right: *const Expr },
};

pub fn eval(expr: Expr) i32 {
    return switch (expr) {
        .number => |n| [[SLOT num_eval]],
        .add => |op| [[SLOT add_eval]],
        .multiply => |op| [[SLOT mul_eval]],
    };
}
